(function () {
    const params = new URLSearchParams(window.location.search);
    const query = (params.get('q') || '').trim();
    const input = document.querySelector('[data-search-page-input]');
    const title = document.querySelector('[data-search-title]');
    const count = document.querySelector('[data-search-count]');
    const results = document.querySelector('[data-search-results]');

    if (input) {
        input.value = query;
    }

    if (!query || !results) {
        return;
    }

    const normalized = query.toLowerCase();
    const matched = window.MOVIE_SEARCH_INDEX.filter(function (movie) {
        const haystack = [
            movie.title,
            movie.region,
            movie.type,
            movie.year,
            movie.genre,
            movie.oneLine,
            (movie.tags || []).join(' ')
        ].join(' ').toLowerCase();
        return haystack.includes(normalized);
    }).slice(0, 120);

    if (title) {
        title.textContent = '“' + query + '”的搜索结果';
    }

    if (count) {
        count.textContent = matched.length + ' 部';
    }

    if (!matched.length) {
        results.innerHTML = '<p class="content-card">没有找到匹配内容，请尝试其他关键词。</p>';
        return;
    }

    results.innerHTML = matched.map(function (movie) {
        const tags = (movie.tags || []).slice(0, 3).map(function (tag) {
            return '<span>' + escapeHtml(tag) + '</span>';
        }).join('');

        return [
            '<article class="movie-card">',
            '    <a class="poster-frame" href="' + movie.url + '">',
            '        <img src="' + movie.cover + '" alt="' + escapeHtml(movie.title) + '" loading="lazy">',
            '        <span class="poster-badge">' + escapeHtml(movie.region) + '</span>',
            '        <span class="poster-play">播放</span>',
            '    </a>',
            '    <div class="movie-card-body">',
            '        <h3><a href="' + movie.url + '">' + escapeHtml(movie.title) + '</a></h3>',
            '        <p>' + escapeHtml(movie.oneLine) + '</p>',
            '        <div class="movie-meta">',
            '            <span>★ ' + movie.rating + '</span>',
            '            <span>' + escapeHtml(movie.year) + '</span>',
            '            <span>' + Number(movie.views).toLocaleString() + ' 次</span>',
            '        </div>',
            '        <div class="tag-row">' + tags + '</div>',
            '    </div>',
            '</article>'
        ].join('\n');
    }).join('\n');

    function escapeHtml(value) {
        return String(value).replace(/[&<>"]/g, function (character) {
            return {
                '&': '&amp;',
                '<': '&lt;',
                '>': '&gt;',
                '"': '&quot;'
            }[character];
        });
    }
})();
